//------------------------------------------------------------------------------
//Callback Name: initialize_cb
//------------------------------------------------------------------------------
void a2::initialize_cb()
{
    try
    {
        UF_initialize();

        group0 = dynamic_cast<NXOpen::BlockStyler::Group*>(theDialog->TopBlock()->FindBlock("group0"));
        button0 = dynamic_cast<NXOpen::BlockStyler::Button*>(theDialog->TopBlock()->FindBlock("button0"));
        button01 = dynamic_cast<NXOpen::BlockStyler::Button*>(theDialog->TopBlock()->FindBlock("button01"));
        group = dynamic_cast<NXOpen::BlockStyler::Group*>(theDialog->TopBlock()->FindBlock("group"));
        selection0 = dynamic_cast<NXOpen::BlockStyler::SelectObject*>(theDialog->TopBlock()->FindBlock("selection0"));
        toggle0 = dynamic_cast<NXOpen::BlockStyler::Toggle*>(theDialog->TopBlock()->FindBlock("toggle0"));
        group1 = dynamic_cast<NXOpen::BlockStyler::Group*>(theDialog->TopBlock()->FindBlock("group1"));
        point0 = dynamic_cast<NXOpen::BlockStyler::SpecifyPoint*>(theDialog->TopBlock()->FindBlock("point0"));
        enum0 = dynamic_cast<NXOpen::BlockStyler::Enumeration*>(theDialog->TopBlock()->FindBlock("enum0"));
        group2 = dynamic_cast<NXOpen::BlockStyler::Group*>(theDialog->TopBlock()->FindBlock("group2"));
        point01 = dynamic_cast<NXOpen::BlockStyler::SpecifyPoint*>(theDialog->TopBlock()->FindBlock("point01"));
        enum01 = dynamic_cast<NXOpen::BlockStyler::Enumeration*>(theDialog->TopBlock()->FindBlock("enum01"));

        // 设置手动点块为可选
        setPointOptional(point0);
        setPointOptional(point01);

        UF_terminate();
    }
    catch(exception& ex)
    {
        UF_terminate();
        a2::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
}

//------------------------------------------------------------------------------
//Callback Name: dialogShown_cb
//This callback is executed just before the dialog launch. Thus any value set 
//here will take precedence and dialog will be launched showing that value. 
//------------------------------------------------------------------------------
void a2::dialogShown_cb()
{
    try
    {
        UF_initialize();

        // 初始状态：toggle0 未选中 = 单选
        toggle0->SetValue(false);

        // 同步设置 selection0 为单选模式
        BlockStyler::PropertyList* selectionProps = selection0->GetProperties();
        if (selectionProps)
        {
            selectionProps->SetLogical("AllowMultipleSelection", false);
            delete selectionProps;
        }

        UF_terminate();
    }
    catch(exception& ex)
    {
        UF_terminate();
        a2::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
}

//------------------------------------------------------------------------------
//Callback Name: apply_cb
//------------------------------------------------------------------------------
int a2::apply_cb()
{
    int errorCode = 0;
    try
    {
        g_session = theSession;
        g_ui = theUI;
        g_workPart = g_session->Parts()->Work();

        if (!executeFromDialog())
            errorCode = 1;
    }
    catch(exception& ex)
    {
        errorCode = 1;
        a2::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}

//------------------------------------------------------------------------------
//Callback Name: update_cb
//------------------------------------------------------------------------------
int a2::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
    try
    {
        if(block == button0)
        {
            // 点击"移动"按钮
            m_operationMode = OperationMode::Move;
            theSession->ListingWindow()->Open();
            theSession->ListingWindow()->WriteLine("已选择移动模式");
        }
        else if(block == button01)
        {
            // 点击"复制"按钮
            m_operationMode = OperationMode::Copy;
            theSession->ListingWindow()->Open();
            theSession->ListingWindow()->WriteLine("已选择复制模式");
        }
        else if(block == selection0)
        {
            // 选择操作对象 — 获取当前已选对象数量
            std::vector<TaggedObject*> selected = selection0->GetSelectedObjects();
            theSession->ListingWindow()->Open();
            theSession->ListingWindow()->WriteLine("已选择 " + std::to_string(selected.size()) + " 个对象");
        }
        else if(block == toggle0)
        {
            // 切换单选/多选模式
            UF_initialize();

            bool isMultiSelect = toggle0->Value();
            BlockStyler::PropertyList* selectionProps = selection0->GetProperties();
            if (selectionProps)
            {
                selectionProps->SetLogical("AllowMultipleSelection", isMultiSelect);
                delete selectionProps;
            }

            theSession->ListingWindow()->Open();
            theSession->ListingWindow()->WriteLine(
                isMultiSelect ? "已切换为多选模式，可同时选择多个对象" : "已切换为单选模式，每次只能选择一个对象");

            UF_terminate();
        }
        else if(block == point0)
        {
            // 手动指定起点 — 无特殊逻辑
        }
        else if(block == enum0)
        {
            // 起点模式切换
            int mode = getEnumValue(enum0);
            theSession->ListingWindow()->Open();
            theSession->ListingWindow()->WriteLine("起点模式已切换，当前值: " + std::to_string(mode));
        }
        else if(block == point01)
        {
            // 手动指定终点 — 无特殊逻辑
        }
        else if(block == enum01)
        {
            // 终点模式切换
            int mode = getEnumValue(enum01);
            theSession->ListingWindow()->Open();
            theSession->ListingWindow()->WriteLine("终点模式已切换，当前值: " + std::to_string(mode));
        }
    }
    catch(exception& ex)
    {
        a2::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return 0;
}

//------------------------------------------------------------------------------
//Callback Name: ok_cb
//------------------------------------------------------------------------------
int a2::ok_cb()
{
    int errorCode = 0;
    try
    {
        g_session = theSession;
        g_ui = theUI;
        g_workPart = g_session->Parts()->Work();

        if (!executeFromDialog())
            errorCode = 1;
    }
    catch(exception& ex)
    {
        errorCode = 1;
        a2::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}

