//------------------------------------------------------------------------------
// Function Name: executeFromDialog
// Description: 从对话框读取参数并执行移动/复制操作
//------------------------------------------------------------------------------
bool a2::executeFromDialog()
{
    Session::UndoMarkId undoMark = theSession->SetUndoMark(
        Session::MarkVisibilityVisible, "点到点移动与复制");

    try
    {
        if (m_operationMode == OperationMode::None)
            throw std::runtime_error("请先点击「移动」或「复制」按钮选择操作模式");

        // 读取所选对象
        TaggedObject* primaryObject = readPrimaryObject(selection0);
        std::vector<tag_t> selectedTags = readSelectedTransformTags(selection0);

        if (!primaryObject || selectedTags.empty())
            throw std::runtime_error("请选择操作对象");

        // 读取起点模式与终点模式
        StartPointMode startMode = static_cast<StartPointMode>(getEnumValue(enum0));
        FinishPointMode finishMode = static_cast<FinishPointMode>(getEnumValue(enum01));

        // 解析起点和终点
        Point3d start = resolveStartPoint(startMode, primaryObject, point0);
        Point3d finish = resolveFinishPoint(finishMode, primaryObject, start, point01);

        // 计算位移向量
        Vector3d translation(finish.X - start.X, finish.Y - start.Y, finish.Z - start.Z);

        // 执行移动或复制
        executeMoveOrCopy(selectedTags, translation, m_operationMode);

        // 更新建模
        if (theSession && theSession->UpdateManager())
            theSession->UpdateManager()->DoUpdate(undoMark);

        // 信息输出
        theSession->ListingWindow()->Open();
        theSession->ListingWindow()->WriteLine(
            std::string(m_operationMode == OperationMode::Move ? "移动" : "复制") +
            "完成，操作对象数: " + std::to_string(selectedTags.size()));

        UF_DISP_refresh();
        return true;
    }
    catch (const NXException& ex)
    {
        theSession->UndoToMark(undoMark, "点到点移动与复制");
        a2::theUI->NXMessageBox()->Show("错误", NXOpen::NXMessageBox::DialogTypeError, ex.Message());
    }
    catch (const std::exception& ex)
    {
        theSession->UndoToMark(undoMark, "点到点移动与复制");
        a2::theUI->NXMessageBox()->Show("错误", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return false;
}
